1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Step = QuoteStep;
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
17	
18	const FIRST_INSURANCE_RATE = 0.1;
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	const BLOCK_SIZE = 3;
22	const BLOCK_BASE_PREMIUM = 60;
23	
24	const countByType = (items: Item[]): Map<string, number> => {
25	  const counts = new Map<string, number>();
26	  for (const item of items) {
27	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
28	  }
29	  return counts;
30	};
31	
32	const groupBase = (type: string, count: number): number =>
33	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
34	    ? BLOCK_BASE_PREMIUM
35	    : count * basePremiumFor(type);
36	
37	const policyBase = (items: Item[]): number => {
38	  let total = 0;
39	  for (const [type, count] of countByType(items)) {
40	    total += groupBase(type, count);
41	  }
42	  return total;
43	};
44	
45	const quotePremium = (items: Item[]): number => {
46	  const base = policyBase(items);
47	  const firstInsurance = base * FIRST_INSURANCE_RATE;
48	  return Math.ceil(base + firstInsurance + PROCESSING_FEE);
49	};
50	
51	export const processScenario = (scenario: Scenario): unknown => {
52	  const results = scenario.steps.map((step) => ({
53	    premium: quotePremium(step.items),
54	  }));
55	  return { results };
56	};
